 Einmal schießen — Magic Bullet\nsofort auf Murder (durch Wände, von dir aus)",Color3.fromRGB(20,50,120),function() if (mm2_getRole(LP_MM)~="sheriff") then setStatus("❌ Du bist nicht der Sheriff!",Color3.fromRGB(255,60,60));return;end task.spawn(function() local myChar=LP_MM.Character;local myHum=myChar and myChar:FindFirstChildOfClass("Humanoid") ;local myHrp=myChar and myChar:FindFirstChild("HumanoidRootPart") ;if ( not myHum or  not myHrp) then return;end local gun=mm2_getGun(myChar,myHum);task.wait(0.08);for _,plr in ipairs(Players_MM:GetPlayers()) do if ((plr~=LP_MM) and (mm2_getRole(plr)=="murder")) then local tChar=plr.Character;local tHrp=tChar and tChar:FindFirstChild("HumanoidRootPart") ;local tHum=tChar and tChar:FindFirstChildOfClass("Humanoid") ;if (tHrp and tHum and (tHum.Health>0)) then mm2_magicShoot(gun,myHrp,tHrp,tHum,tChar);setStatus("🎯 Magic Bullet → "   .. plr.Name   .. "!" ,Color3.fromRGB(60,200,100));end break;end end end);end);mm2Section("☠️  KILL ALL (als Murder)");local mm2_killAllActive=false;local function mm2_equipKnife() local myChar=LP_MM.Character;local myHum=myChar and myChar:FindFirstChildOfClass("Humanoid") ;local myBp=LP_MM:FindFirstChild("Backpack");if  not myHum then return nil;end local knife=nil;for _,nm in ipairs(MM2_KNIFE_NAMES) do knife=(myChar and myChar:FindFirstChild(nm)) or (myBp and myBp:FindFirstChild(nm)) ;if knife then break;end end if ( not knife and myBp) then for _,obj in ipairs(myBp:GetChildren()) do if obj:IsA("Tool") then local n=obj.Name:lower();if (n:find("knife") or n:find("blade") or n:find("dagger")) then knife=obj;break;end end end end if (knife and knife:IsA("Tool")) then pcall(function() myHum:EquipTool(knife);end);task.wait(0.06);end return knife;end local function mm2_killAllNow() local myChar=LP_MM.Character;local myHrp=myChar and myChar:FindFirstChild("HumanoidRootPart") ;if  not myHrp then return 0;end local origCF=myHrp.CFrame;local knife=mm2_equipKnife();local fti=nil;pcall(function() if (type(f