n;end if VIM then pcall(function() VIM:SendMouseButtonEvent(0,0,1,true,game,0);VIM:SendMouseButtonEvent(0,0,1,false,game,0);end);end return;end if mouse1click then pcall(function() mouse1click();end);return;end if (mouse1press and mouse1release) then pcall(function() mouse1press();end);pcall(function() mouse1release();end);return;end if VIM then pcall(function() VIM:SendMouseButtonEvent(0,0,0,true,game,0);VIM:SendMouseButtonEvent(0,0,0,false,game,0);end);end end local function startLoop() ac.runId=ac.runId + 1 ;local myId=ac.runId;task.spawn(function() while ac.active and ac.enabled and (myId==ac.runId)  do local fire=doMouseClick;local cps=ac.cps;if (cps<1) then cps=1;end if (cps<=60) then fire();task.wait(1/cps );else ac.accum=(ac.accum or 0) + (cps/60) ;local perTick=math.floor(ac.accum);ac.accum=ac.accum-perTick ;if (perTick<1) then perTick=1;end for _=1,perTick do if  not (ac.active and ac.enabled and (myId==ac.runId)) then break;end fire();end task.wait(1/60 );end end end);end CombatTab:CreateToggle({Name="🖥 Auto Klicker aktivieren",CurrentValue=false,Callback=function(state) ac.enabled=state;if  not state then ac.active=false;ac.runId=ac.runId + 1 ;end end});CombatTab:CreateDropdown({Name="Modus",Options={"Halten","Umschalten"},CurrentOption={"Halten"},Callback=function(opt) local v=((type(opt)=="table") and opt[1]) or opt ;if v then ac.mode=v;end end});CombatTab:CreateDropdown({Name="Welche Maustaste",Options={"Links","Rechts"},CurrentOption={"Links"},Callback=function(opt) local v=((type(opt)=="table") and opt[1]) or opt ;if v then ac.mouseButton=v;end end});CombatTab:CreateSlider({Name="Klicks pro Sekunde (CPS) — Geschwindigkeit",Range={1,300},Increment=1,Suffix=" CPS",CurrentValue=12,Callback=function(v) ac.cps=v;end});CombatTab:CreateDropdown({Name="Auslöser-Maustaste (halten zum Klicken)",Options={"Maus Rechts","Maus Mitte","Maus Links"},CurrentOption={"Maus Rechts"},Callback=function(opt) local v=((type(opt)=="table") and opt[1]) or opt ;if v then ac.a